Функция ДействующийДоговорНаДату(Контрагент, ДатаСреза)

    Запрос = Новый Запрос;
    Запрос.Текст = 
        "ВЫБРАТЬ ПЕРВЫЕ 1
        |	Договоры.Ссылка КАК Ссылка
        |ИЗ
        |	Справочник.Договоры КАК Договоры
        |ГДЕ
        |	Договоры.Владелец = &Владелец
        |	И Договоры.ДатаНачала <= &ДатаСреза
        |	И (Договоры.ДатаОкончания = НЕОПРЕДЕЛЕНО ИЛИ Договоры.ДатаОкончания >= &ДатаСреза)
        |УПОРЯДОЧИТЬ ПО
        |	Договоры.ДатаНачала УБЫВ";

    Запрос.УстановитьПараметр("Владелец", Контрагент);
    Запрос.УстановитьПараметр("ДатаСреза", ДатаСреза);

    Результат = Запрос.Выполнить();

    Если Результат.Пустой() Тогда
        Возврат Неопределено;
    КонецЕсли;

    Выборка = Результат.Выбрать();
    Выборка.Следующий();

    Возврат Выборка.Ссылка;

КонецФункции
